 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	import classNames from 'classnames';
 4	
 5	import { K8sGroupVersionKind } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Label as PfLabel, LabelGroup as PfLabelGroup } from '@patternfly/react-core';
 7	import MutedText from '@utils/components/MutedText/MutedText';
 8	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 9	import { isEmpty } from '@utils/utils';
10	
11	export type LabelProps = {
12	  expand: boolean;
13	  groupVersionKind: K8sGroupVersionKind;
14	  name: string;
15	  value: string;
16	};
17	
18	export const Label: FC<LabelProps> = ({ expand, groupVersionKind, name, value }) => {
19	  const href = `/search?kind=${groupVersionKind.kind}&q=${
20	    value ? encodeURIComponent(`${name}=${value}`) : name
21	  }`;
22	  const kindOf = `co-m-${groupVersionKind.kind}`;
23	  const klass = classNames(kindOf, { 'co-m-expand': expand }, 'co-label');
24	
25	  return (
26	    <>
27	      <PfLabel className={klass}>
28	        <Link className="pf-v6-c-label__content" to={href}>
29	          <span className="co-label__key" data-test="label-key">
30	            {name}
31	          </span>
32	          {value && <span className="co-label__eq">=</span>}
33	          {value && <span className="co-label__value">{value}</span>}
34	        </Link>
35	      </PfLabel>
36	    </>
37	  );
38	};
39	
40	type LabelListProps = {
41	  expand?: boolean;
42	  groupVersionKind: K8sGroupVersionKind;
43	  labels: { [key: string]: string };
44	};
45	
46	export const LabelList: FC<LabelListProps> = ({ expand = true, groupVersionKind, labels }) => {
47	  const { t } = useNetworkingTranslation();
48	
49	  const list = Object.entries(labels || []).map(([label, key]) => (
50	    <Label expand={expand} groupVersionKind={groupVersionKind} key={key} name={key} value={label} />
51	  ));
52	
53	  return (
54	    <>
55	      {isEmpty(list) ? (
56	        <MutedText content={t('No labels')} key="0">
57	          {t('No labels')}
58	        </MutedText>
59	      ) : (
60	        <PfLabelGroup
61	          className="co-label-group"
62	          data-test="label-list"
63	          defaultIsOpen={true}
64	          numLabels={20}
65	        >
66	          {list}
67	        </PfLabelGroup>
68	      )}
69	    </>
70	  );
71	};

